"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Christians for Biblical Equality (CBE International)", "org_type": "ministry", "website": "www.cbeinternational.org", "city": null, "state": null, "summary": "The world''s largest egalitarian Christian organization challenging biblical and social barriers to women''s equality. Works with leaders across 100+ denominations globally. Focused on biblical basis for women''s shared and equal leadership in home, church, and world.", "fit_score": 9, "fit_reason": "Established, well-documented global organization with clear gender justice mission. Multi-denominational reach, strong academic/theological foundation, 30+ years operating. Direct alignment with gender equality in Christian ministry.", "source_query": "female Christian leaders organizations gender equality ministry", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "CHRISTUS Health", "org_type": "ministry", "website": "christushealth.org", "city": "San Antonio", "state": "TX", "summary": "60-hospital Catholic network. CEO Ernie Sadau (since 2011). CHRISTUS Foundation for HealthCare with $3M+ giving capacity. CEO established endowment for healthcare education leadership.", "fit_score": 9, "fit_reason": "Long-tenured Catholic CEO, documented foundation with giving platform, personal philanthropic commitment to healthcare leadership development", "source_query": "Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Church World Service (CWS)", "org_type": "ministry", "website": "cwsglobal.org", "city": null, "state": null, "summary": "Coalition of 37 Christian denominations working together to support refugees and immigrants. Provides housing, employment, and school enrollment assistance with church partnerships across the U.S. Active advocacy for refugee resettlement policies.", "fit_score": 9, "fit_reason": "Large interfaith coalition with extensive public ministry platforms, church partnerships, documented giving through denominational networks, and advocacy presence", "source_query": "refugee resettlement Christian agencies nonprofit fundraising", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "CiRCE Institute", "org_type": "ministry", "website": "circeinstitute.org", "city": "Kannapolis", "state": "NC", "summary": "Classical Christian education research, training, and consulting ministry. Provides teacher training, Lost Tools of Writing curriculum, and classical education resources for schools and homeschools.", "fit_score": 9, "fit_reason": "501(c)(3) with documented donate page and Building Fund; Andrew Kern serves as president and regular fundraising speaker", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Classical Conversations Foundation", "org_type": "ministry", "website": "classicalconversations.com", "city": "Multiple", "state": "US", "summary": "Nonprofit foundation supporting Christian classical education globally. Operates Homeschool Families on Missions program providing grants for student mission trips.", "fit_score": 9, "fit_reason": "Explicit giving opportunities documented; foundation specifically encourages $1.10 donations per student for mission support", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Colorado Christian University", "org_type": "ministry", "website": "ccu.edu", "city": "Denver", "state": "CO", "summary": "Private Christian university with active giving platform including CCU Gives Day 2026 and President''s Weekend donor events that annually raise millions. President Eric Hogue is a published author on fundraising and philanthropy.", "fit_score": 9, "fit_reason": "Documented giving platform, President''s Weekend raising $5.9M+ annually, active CCU Gives Day campaign, president actively promotes donor-centric fundraising", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Community Peacemaker Teams (CPT)", "org_type": "ministry", "website": "cpt.org", "city": null, "state": null, "summary": "International organization supporting peace worker teams in conflict areas. Backed by Mennonite churches and peace churches of North America. Operates in Palestine, Colombia, Canada (Indigenous Rights), and Kurdistan. Does not accept government funding.", "fit_score": 9, "fit_reason": "Largest Christian peace team organization, operates in active conflict zones, has dedicated donor base of thousands of supporters and hundreds of congregations, publicly raises funds", "source_query": "Community Peacemaker Teams Christian donations", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}]'::jsonb)
  as x(org_name text, org_type text, website text, city text, state text,
       summary text, fit_score int, fit_reason text, source_query text, meta jsonb)),
-- Count how many existing rows (queue + pipeline) share each URL.
-- A URL on exactly one row is a person-specific page safe to dedup
-- against; a URL shared by many is a roster/platform page and must
-- NOT cause a skip, or we'd drop distinct people who list it.
existing_sites as (
  select site, count(*) as n from (
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.scout_candidates where website is not null and btrim(website) <> ''
    union all
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.leads where website is not null and btrim(website) <> ''
  ) w group by site)
insert into sales.scout_candidates
  (org_name, org_type, website, city, state, summary,
   fit_score, fit_reason, source_query, status, meta)
select s.org_name, s.org_type, s.website, s.city, s.state, s.summary,
       s.fit_score, s.fit_reason, s.source_query, 'pending', coalesce(s.meta, '{}'::jsonb)
from src s
where not exists (select 1 from sales.scout_candidates c
                  where lower(trim(c.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from sales.leads l
                  where lower(trim(l.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from existing_sites es
                  where s.website is not null and btrim(s.website) <> ''
                    and es.n = 1
                    and es.site = rtrim(lower(regexp_replace(s.website, '^https?://(www\.)?', '', 'i')), '/'));